(function(global) {
    function IOBase(key, title, socket, multipleConnections) {
        this.key = key;
        this.title = title;
        this.socket = socket;
        this.multipleConnections = !!multipleConnections;
        this.node = null;
    }

    function Input(key, title, socket, multipleConnections) {
        IOBase.call(this, key, title, socket, multipleConnections);
    }
    Input.prototype = Object.create(IOBase.prototype);
    Input.prototype.constructor = Input;

    function Output(key, title, socket, multipleConnections) {
        IOBase.call(this, key, title, socket, multipleConnections);
    }
    Output.prototype = Object.create(IOBase.prototype);
    Output.prototype.constructor = Output;

    function Socket(name) {
        this.name = name;
    }

    function Node(name) {
        this.name = name;
        this.id = null;
        this.data = {};
        this.meta = {};
        this.position = [0, 0];
        this.inputs = new Map();
        this.outputs = new Map();
    }
    Node.prototype.addInput = function(input) {
        input.node = this;
        this.inputs.set(input.key, input);
        return this;
    };
    Node.prototype.addOutput = function(output) {
        output.node = this;
        this.outputs.set(output.key, output);
        return this;
    };

    function Connection(output, input) {
        this.output = output;
        this.input = input;
        this.id = null;
        this.data = {};
    }

    function NodeEditor(namespace, container) {
        this.namespace = namespace;
        this.container = container;
    }

    global.Rete = {
        NodeEditor: NodeEditor,
        Socket: Socket,
        Node: Node,
        Input: Input,
        Output: Output,
        Connection: Connection
    };
})(window);
